125→interface HeroPortraitModelProps {
126→  race: Race;
127→}
128→
129→export default function HeroPortraitModel(props: HeroPortraitModelProps) {
130→  let canvasRef!: HTMLCanvasElement;
131→  let gl: WebGLRenderingContext | WebGL2RenderingContext | null = null;
132→  let modelRenderer: ModelRenderer | null = null;
133→  let resizeObserver: ResizeObserver | null = null;
134→  let rafId = 0;
135→  let disposed = false;
136→  let initVersion = 0;
137→
138→  const mvMatrix = mat4.create();
139→  const pMatrix = mat4.create();
140→  const worldCameraMatrix = mat4.create();
141→  const cameraPos = vec3.create();
142→  const cameraTarget = vec3.create();
143→  const cameraQuat = quat.create();
144→  let cameraFov = 0.691111;
145→  let cameraNear = 8;
146→  let cameraFar = 1800;
147→
148→  const destroyRenderer = () => {
149→    if (!modelRenderer) return;
150→    try {
151→      modelRenderer.destroy();
152→    } catch (err) {
153→      console.warn('hero portrait renderer destroy failed', err);
154→    } finally {
155→      modelRenderer = null;
156→    }
157→  };
158→
159→  const updateProjection = () => {
160→    if (!canvasRef) return;
161→    const aspect = Math.max(1e-6, canvasRef.clientWidth / Math.max(1, canvasRef.clientHeight));
162→    mat4.perspective(pMatrix, cameraFov, aspect, cameraNear, cameraFar);
163→  };
164→
165→  const resizeCanvas = () => {
166→    if (!canvasRef || !gl) return;
167→    const dpr = window.devicePixelRatio || 1;
168→    const w = Math.max(1, Math.round(canvasRef.clientWidth * dpr));
169→    const h = Math.max(1, Math.round(canvasRef.clientHeight * dpr));
170→    if (canvasRef.width !== w || canvasRef.height !== h) {
171→      canvasRef.width = w;
172→      canvasRef.height = h;
173→    }
174→    gl.viewport(0, 0, w, h);
175→    updateProjection();
176→  };
177→
178→  const configureCamera = (model: ModelType) => {
179→    const cam = model.Cameras?.[0];
180→    if (cam) {
181→      vec3.set(cameraPos, cam.Position[0], cam.Position[1], cam.Position[2]);
182→      vec3.set(cameraTarget, cam.TargetPosition[0], cam.TargetPosition[1], cam.TargetPosition[2]);
183→      cameraFov = Math.max(0.35, cam.FieldOfView || 0.691111);
184→      cameraNear = Math.max(4, cam.NearClip || 8);
185→      cameraFar = Math.max(cameraNear + 100, cam.FarClip || 1800);
186→      mat4.lookAt(mvMatrix, cameraPos, cameraTarget, vec3.fromValues(0, 0, 1));
187→    } else {
188→      const min = model.Info?.MinimumExtent;
189→      const max = model.Info?.MaximumExtent;
190→      if (min && max) {
191→        const cx = (min[0] + max[0]) * 0.5;
192→        const cy = (min[1] + max[1]) * 0.5;
193→        const cz = (min[2] + max[2]) * 0.5;
194→        const radius = Math.max(140, model.Info?.BoundsRadius || 180);
195→        vec3.set(cameraPos, cx + radius * 0.2, cy - radius * 1.8, cz + radius * 0.2);
196→        vec3.set(cameraTarget, cx, cy, cz);
197→      } else {
198→        vec3.set(cameraPos, 0, -450, 120);
199→        vec3.set(cameraTarget, 0, 0, 110);
200→      }
201→      cameraFov = 0.691111;
202→      cameraNear = 8;
203→      cameraFar = 1800;
204→      mat4.lookAt(mvMatrix, cameraPos, cameraTarget, vec3.fromValues(0, 0, 1));
205→    }
206→
207→    if (mat4.invert(worldCameraMatrix, mvMatrix)) {
208→      const rot = mat3.create();
209→      mat3.fromMat4(rot, worldCameraMatrix);
210→      quat.fromMat3(cameraQuat, rot);
211→      quat.normalize(cameraQuat, cameraQuat);
212→    } else {
213→      quat.identity(cameraQuat);
214→    }
215→  };
216→
217→  const startRenderLoop = () => {
218→    let lastTs = performance.now();
219→    const tick = (now: number) => {
220→      if (disposed) return;
221→      rafId = requestAnimationFrame(tick);
222→      if (!gl || !modelRenderer) return;
223→
224→      resizeCanvas();
225→      const delta = Math.min(100, now - lastTs);
226→      lastTs = now;
227→      modelRenderer.update(delta);
228→      gl.clearColor(0, 0, 0, 0);
229→      gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
230→      modelRenderer.render(mvMatrix, pMatrix, { env: false, wireframe: false });
231→    };
232→    rafId = requestAnimationFrame(tick);
233→  };
234→
235→  const initForRace = async (race: Race) => {
236→    const version = ++initVersion;
237→    const model = await loadModel(race);
238→    if (disposed || version !== initVersion || !gl) return;
239→
240→    destroyRenderer();
241→    modelRenderer = new ModelRenderer(model);
242→    modelRenderer.initGL(gl);
243→    configureCamera(model);
244→    modelRenderer.setCamera(cameraPos, cameraQuat);
245→    modelRenderer.setLightPosition(cameraPos);
246→    modelRenderer.setLightColor(vec3.fromValues(1, 1, 1));
247→    modelRenderer.setSequence(findPortraitSequenceIndex(model));
248→
249→    const texturePromises = (model.Textures || []).map(async (tex) => {
250→      const texturePath = getTexturePath(tex.Image, race);
251→      if (!texturePath) return;
252→      const mips = await loadBLPMips(texturePath);
253→      if (!disposed && version === initVersion) {
254→        modelRenderer!.setTextureImageData(tex.Image, mips);
255→      }
256→    });
257→    await Promise.all(texturePromises);
258→  };
259→
260→  onMount(() => {
261→    gl = canvasRef.getContext('webgl2', {
262→      alpha: true,
263→      premultipliedAlpha: false,
264→      antialias: true,
265→      depth: true,
266→      stencil: false,
267→    }) as WebGL2RenderingContext | null;
268→    if (!gl) {
269→      gl = canvasRef.getContext('webgl', {
270→        alpha: true,
271→        premultipliedAlpha: false,
272→        antialias: true,
273→        depth: true,
274→        stencil: false,
275→      });
276→    }
277→    if (!gl) return;
278→
279→    resizeCanvas();
280→    resizeObserver = new ResizeObserver(() => resizeCanvas());
281→    resizeObserver.observe(canvasRef);
282→    startRenderLoop();
283→    void initForRace(props.race).catch((err) => console.error(err));
284→  });
285→
286→  createEffect(() => {
287→    const race = props.race;
288→    if (!gl) return;
289→    void initForRace(race).catch((err) => console.error(err));
290→  });
291→
292→  onCleanup(() => {
293→    disposed = true;
294→    initVersion++;
295→    cancelAnimationFrame(rafId);
296→    resizeObserver?.disconnect();
297→    destroyRenderer();
298→  });
299→
300→  return (
301→    <canvas
302→      ref={canvasRef}
303→      style={{
304→        position: 'absolute',
305→        inset: '0',
306→        width: '100%',
307→        height: '100%',
308→        display: 'block',
309→        'pointer-events': 'none',
310→      }}
311→    />
312→  );
313→}
