102→  if (mips.length === 0) {
103→    throw new Error(`No mip levels decoded for worker unit texture: ${path}`);
104→  }
105→
106→  blpCache.set(path, mips);
107→  return mips;
108→}
109→
110→function findIdleSequenceIndex(model: ModelType, race: Race): number {
111→  const sequences = model.Sequences || [];
112→  if (sequences.length === 0) return 0;
113→
114→  const sequenceNames = sequences.map((seq) => (seq.Name || '').toLowerCase());
115→  const preferencesByRace: Record<Race, readonly string[]> = {
116→    Human: [
117→      'stand work',
118→      'stand lumber',
119→      'stand ready',
120→      'stand gold',
121→      'stand - 3',
122→      'stand -3',
123→      'stand 2',
124→      'stand - 2',
125→      'stand',
126→    ],
127→    Orc: [
128→      'stand ready',
129→      'stand - stretch',
130→      'stand - itch head',
131→      'stand - talk gesture',
132→      'stand 2',
133→      'stand - 2',
134→      'stand',
135→    ],
136→    NightElf: [
137→      'stand ready',
138→      'stand - 3',
139→      'stand -3',
140→      'stand 2',
141→      'stand - 2',
142→      'stand',
143→    ],
144→    Undead: [
145→      'stand work',
146→      'stand 2',
147→      'stand - 2',
148→      'stand ready',
149→      'stand',
150→    ],
151→  };
152→  const preferences = preferencesByRace[race];
153→
154→  for (const pref of preferences) {
155→    const idx = sequenceNames.findIndex((name) => name.includes(pref));
156→    if (idx >= 0) return idx;
157→  }
158→
159→  const fallback = sequenceNames.findIndex(
160→    (name) => name.includes('stand') && !name.includes('death') && !name.includes('decay'),
161→  );
162→  return fallback >= 0 ? fallback : 0;
163→}
164→
165→function getSequenceInterval(model: ModelType, index: number): { start: number; length: number } {
166→  const seq = model.Sequences?.[index];
167→  const start = seq?.Interval?.[0] ?? 0;
168→  const end = seq?.Interval?.[1] ?? (start + 1000);
169→  return { start, length: Math.max(1, end - start) };
170→}
171→
172→function getExtentsForSequence(model: ModelType, sequenceIndex: number): {
173→  min: readonly [number, number, number] | null;
174→  max: readonly [number, number, number] | null;
175→} {
176→  const seq = model.Sequences?.[sequenceIndex];
177→  const seqMin = seq?.MinimumExtent;
178→  const seqMax = seq?.MaximumExtent;
179→  if (seqMin && seqMax) {
180→    return {
181→      min: [seqMin[0], seqMin[1], seqMin[2]],
182→      max: [seqMax[0], seqMax[1], seqMax[2]],
183→    };
184→  }
185→
186→  const modelMin = model.Info?.MinimumExtent;
187→  const modelMax = model.Info?.MaximumExtent;
188→  if (modelMin && modelMax) {
189→    return {
190→      min: [modelMin[0], modelMin[1], modelMin[2]],
191→      max: [modelMax[0], modelMax[1], modelMax[2]],
192→    };
193→  }
194→
195→  return { min: null, max: null };
196→}
