198→interface WorkerUnitModelProps {
199→  race: Race;
200→  side: WorkerSide;
201→}
202→
203→export default function WorkerUnitModel(props: WorkerUnitModelProps) {
204→  let canvasRef!: HTMLCanvasElement;
205→  let gl: WebGLRenderingContext | WebGL2RenderingContext | null = null;
206→  let modelRenderer: ModelRenderer | null = null;
207→  let resizeObserver: ResizeObserver | null = null;
208→  let rafId = 0;
209→  let disposed = false;
210→  let initVersion = 0;
211→
212→  let sequenceIndex = 0;
213→  let sequenceStart = 0;
214→  let sequenceLength = 1000;
215→  let animStartMs = 0;
216→
217→  const mvMatrix = mat4.create();
218→  const pMatrix = mat4.create();
219→  const worldCameraMatrix = mat4.create();
220→  const cameraPos = vec3.create();
221→  const cameraTarget = vec3.create();
222→  const cameraQuat = quat.create();
223→  let cameraFov = 0.78;
224→  let cameraNear = 8;
225→  let cameraFar = 2400;
226→
227→  const destroyRenderer = () => {
228→    if (!modelRenderer) return;
229→    try {
230→      modelRenderer.destroy();
231→    } catch (err) {
232→      console.warn('worker unit renderer destroy failed', err);
233→    } finally {
234→      modelRenderer = null;
235→    }
236→  };
237→
238→  const updateProjection = () => {
239→    if (!canvasRef) return;
240→    const aspect = Math.max(1e-6, canvasRef.clientWidth / Math.max(1, canvasRef.clientHeight));
241→    mat4.perspective(pMatrix, cameraFov, aspect, cameraNear, cameraFar);
242→  };
243→
244→  const resizeCanvas = () => {
245→    if (!canvasRef || !gl) return;
246→    const dpr = window.devicePixelRatio || 1;
247→    const w = Math.max(1, Math.round(canvasRef.clientWidth * dpr));
248→    const h = Math.max(1, Math.round(canvasRef.clientHeight * dpr));
249→    if (canvasRef.width !== w || canvasRef.height !== h) {
250→      canvasRef.width = w;
251→      canvasRef.height = h;
252→    }
253→    gl.viewport(0, 0, w, h);
254→    updateProjection();
255→  };
256→
257→  const configureCamera = (model: ModelType, sequenceIdx: number) => {
258→    const extents = getExtentsForSequence(model, sequenceIdx);
259→    const extMin = extents.min;
260→    const extMax = extents.max;
261→
262→    if (extMin && extMax) {
263→      const cx = (extMin[0] + extMax[0]) * 0.5;
264→      const cy = (extMin[1] + extMax[1]) * 0.5;
265→      const cz = (extMin[2] + extMax[2]) * 0.5;
266→      const dx = extMax[0] - extMin[0];
267→      const dy = extMax[1] - extMin[1];
268→      const dz = extMax[2] - extMin[2];
269→      const rawRadius = Math.hypot(dx, dy, dz) * 0.5;
270→      const radius = Math.min(190, Math.max(100, rawRadius));
271→      const height = Math.min(220, Math.max(90, dz));
272→      const lateralOffset = radius * 0.42;
273→      const distanceMultiplier = 2.25;
274→      const verticalMultiplier = 0.62;
275→
276→      vec3.set(
277→        cameraPos,
278→        cx + lateralOffset,
279→        cy - radius * distanceMultiplier,
280→        cz + height * verticalMultiplier,
281→      );
282→      vec3.set(cameraTarget, cx, cy, cz + height * 0.18);
283→
284→      cameraFov = 0.86;
285→      cameraNear = Math.max(8, radius * 0.08);
286→      cameraFar = Math.max(cameraNear + 300, radius * 11.5);
287→    } else {
288→      vec3.set(cameraPos, 48, -420, 180);
289→      vec3.set(cameraTarget, 0, 0, 100);
290→      cameraFov = 0.78;
291→      cameraNear = 8;
292→      cameraFar = 2200;
293→    }
294→
295→    mat4.lookAt(mvMatrix, cameraPos, cameraTarget, vec3.fromValues(0, 0, 1));
296→    if (mat4.invert(worldCameraMatrix, mvMatrix)) {
297→      const rot = mat3.create();
298→      mat3.fromMat4(rot, worldCameraMatrix);
299→      quat.fromMat3(cameraQuat, rot);
300→      quat.normalize(cameraQuat, cameraQuat);
301→    } else {
302→      quat.identity(cameraQuat);
303→    }
304→  };
305→
306→  const startRenderLoop = () => {
307→    const speed = 0.8;
308→    const tick = (now: number) => {
309→      if (disposed) return;
310→      rafId = requestAnimationFrame(tick);
311→      if (!gl || !modelRenderer) return;
312→
313→      resizeCanvas();
314→      const elapsed = (now - animStartMs) * speed;
315→      const frame = sequenceStart + (elapsed % sequenceLength);
316→      modelRenderer.setSequence(sequenceIndex);
317→      modelRenderer.setFrame(frame);
318→      modelRenderer.update(0);
319→      gl.clearColor(0, 0, 0, 0);
320→      gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
321→      modelRenderer.render(mvMatrix, pMatrix, { env: false, wireframe: false });
322→    };
323→    rafId = requestAnimationFrame(tick);
324→  };
325→
326→  const initForRace = async (race: Race, side: WorkerSide) => {
327→    const version = ++initVersion;
328→    const cfg = WORKER_UNIT_CONFIG[race];
329→    const model = await loadModel(cfg.modelPath);
330→    if (disposed || version !== initVersion || !gl) return;
331→
332→    destroyRenderer();
333→    modelRenderer = new ModelRenderer(model);
334→    modelRenderer.initGL(gl);
335→    sequenceIndex = findIdleSequenceIndex(model, race);
336→    const interval = getSequenceInterval(model, sequenceIndex);
337→    sequenceStart = interval.start;
338→    sequenceLength = interval.length;
339→    configureCamera(model, sequenceIndex);
340→    modelRenderer.setCamera(cameraPos, cameraQuat);
341→    modelRenderer.setLightPosition(cameraPos);
342→    modelRenderer.setLightColor(vec3.fromValues(1, 1, 1));
343→    modelRenderer.setSequence(sequenceIndex);
344→    animStartMs = performance.now();
345→
346→    const texturePromises = (model.Textures || []).map(async (tex) => {
347→      const texturePath = getTexturePath(tex.Image, race);
348→      if (!texturePath) return;
349→      try {
350→        const mips = await loadBLPMips(texturePath);
351→        if (!disposed && version === initVersion) {
352→          modelRenderer!.setTextureImageData(tex.Image, mips);
353→        }
354→      } catch (err) {
355→        console.warn(`failed to load worker texture ${texturePath}`, err);
356→      }
357→    });
358→    await Promise.all(texturePromises);
359→  };
360→
361→  onMount(() => {
362→    gl = canvasRef.getContext('webgl2', {
363→      alpha: true,
364→      premultipliedAlpha: false,
365→      antialias: true,
366→      depth: true,
367→      stencil: false,
368→    }) as WebGL2RenderingContext | null;
369→    if (!gl) {
370→      gl = canvasRef.getContext('webgl', {
371→        alpha: true,
372→        premultipliedAlpha: false,
373→        antialias: true,
374→        depth: true,
375→        stencil: false,
376→      });
377→    }
378→    if (!gl) return;
379→
380→    resizeCanvas();
381→    resizeObserver = new ResizeObserver(() => resizeCanvas());
382→    resizeObserver.observe(canvasRef);
383→    startRenderLoop();
384→    void initForRace(props.race, props.side).catch((err) => console.error(err));
385→  });
386→
387→  createEffect(() => {
388→    const race = props.race;
389→    const side = props.side;
390→    if (!gl) return;
391→    void initForRace(race, side).catch((err) => console.error(err));
392→  });
393→
394→  onCleanup(() => {
395→    disposed = true;
396→    initVersion++;
397→    cancelAnimationFrame(rafId);
398→    resizeObserver?.disconnect();
399→    destroyRenderer();
400→  });
401→
402→  return (
403→    <canvas
404→      ref={canvasRef}
405→      style={{
406→        position: 'absolute',
407→        inset: '0',
408→        width: '100%',
409→        height: '100%',
410→        display: 'block',
411→        'pointer-events': 'none',
412→      }}
413→    />
414→  );
415→}
416→

  1→import { createEffect, createSignal, onCleanup, onMount } from 'solid-js';
  2→import { ModelRenderer, decodeBLP, getBLPImageData, parseMDX } from 'war3-model';
  3→import { mat4, quat, vec3 } from 'gl-matrix';
  4→import { RACE_PREFIXES } from '../state/race';
  5→import type { Race } from '../lib/types';
  6→
  7→type ModelType = ReturnType<typeof parseMDX>;
  8→
  9→const modelCache = new Map<Race, ModelType>();
 10→const blpCache = new Map<string, ImageData[]>();
 11→const widgetMaskCache = new Map<Race, string>();
 12→
 13→function computeVisibleBounds2D(model: ModelType): { minX: number; maxX: number; minY: number; maxY: number } | null {
 14→  let minX = Number.POSITIVE_INFINITY;
 15→  let maxX = Number.NEGATIVE_INFINITY;
 16→  let minY = Number.POSITIVE_INFINITY;
 17→  let maxY = Number.NEGATIVE_INFINITY;
 18→  let hasVisible = false;
 19→  for (const geoset of model.Geosets || []) {
 20→    if (!geoset.Faces || geoset.Faces.length === 0) continue;
 21→    const verts = geoset.Vertices;
 22→    for (let i = 0; i < verts.length; i += 3) {
 23→      const x = verts[i];
 24→      const y = verts[i + 1];
 25→      if (x < minX) minX = x;
 26→      if (x > maxX) maxX = x;
 27→      if (y < minY) minY = y;
 28→      if (y > maxY) maxY = y;
 29→      hasVisible = true;
 30→    }
 31→  }
 32→  if (!hasVisible) return null;
 33→  return { minX, maxX, minY, maxY };
 34→}
 35→
 36→function disableBackdropQuads(model: ModelType): void {
 37→  const hiddenNodes = new Set(['plane01', 'sunrise/set']);
 38→  for (const geoset of model.Geosets || []) {
 39→    const nodeIndex = geoset.Groups?.[0]?.[0];
 40→    if (nodeIndex == null) continue;
 41→    const nodeName = model.Nodes?.[nodeIndex]?.Name?.toLowerCase();
 42→    if (!nodeName || !hiddenNodes.has(nodeName)) continue;
 43→    geoset.Faces = new Uint16Array(0);
 44→  }
 45→}
 46→
 47→function getModelPath(race: Race): string {
 48→  const tile = RACE_PREFIXES[race].tile;
 49→  return `/models/time-indicator/${tile}UI-TimeIndicator.mdx`;
 50→}
 51→
 52→function getClockTexturePath(textureImage: string, race: Race): string | null {
 53→  const norm = textureImage.replaceAll('\\', '/').toLowerCase();
 54→  const tile = RACE_PREFIXES[race].tile;
 55→  const base = `/models/time-indicator/textures/${race}/`;
 56→
 57→  if (norm.includes('genericglowfaded')) return `${base}GenericGlowFaded.blp`;
 58→  if (norm.includes('star3')) return `${base}star3.blp`;
 59→  if (norm.includes('genericglow2_32')) return `${base}GenericGlow2_32.blp`;
 60→  if (norm.includes('timeindicatorframe')) return `${base}${tile}UITile-TimeIndicatorFrame.blp`;
 61→  if (norm.includes('timeindicator')) return `${base}HumanUITile-TimeIndicator.blp`;
 62→  return null;
 63→}
 64→
 65→function getFrameTexturePath(race: Race): string {
 66→  const tile = RACE_PREFIXES[race].tile;
 67→  return `/models/time-indicator/textures/${race}/${tile}UITile-TimeIndicatorFrame.blp`;
 68→}
