144→export default function BordersSection(props: Props) {
145→  const [rendered, setRendered] = createSignal<Record<string, BorderRenderEntry>>({});
146→  const [loading, setLoading] = createSignal(true);
147→
148→  onMount(async () => {
149→    const results = await Promise.all(
150→      ALL_BORDER_PATHS.map(async (path) => {
151→        try {
152→          const rawUrl = await props.loadBlpDataUrl(path);
153→          const previewUrl = await buildBorderPreview(path, rawUrl);
154→          return [path, { previewUrl }] as const;
155→        } catch (e) {
156→          console.warn(`[BordersSection] failed to load ${path}`, e);
157→          return null;
158→        }
159→      }),
160→    );
161→    const map: Record<string, BorderRenderEntry> = {};
162→    for (const r of results) {
163→      if (r) map[r[0]] = r[1];
164→    }
165→    setRendered(map);
166→    setLoading(false);
167→  });
168→
169→  return (
170→    <div class="tab-content">
171→      <div class="section-card">
172→        <h2>Border Textures</h2>
173→        <p class="section-desc">
174→          All {ALL_BORDER_PATHS.length} border BLP textures across {BORDER_CATEGORIES.length} categories.
175→          These 9-slice atlases, bar borders, and panel borders define the chrome around every UI element.
176→        </p>
177→        <Show when={!loading()} fallback={<div class="borders-loading">Decoding border textures…</div>}>
178→          <For each={BORDER_CATEGORIES}>
179→            {(cat) => (
180→              <div class="borders-category">
181→                <h4 class="borders-category-title">{cat.title}</h4>
182→                <p class="borders-category-desc">{cat.desc}</p>
183→                <div class="borders-grid">
184→                  <For each={cat.entries}>
185→                    {(entry) => {
186→                      const image = () => rendered()[entry.path];
187→                      return (
188→                        <Show when={image()}>
189→                          <div class="border-item">
190→                            <img class="border-thumbnail" src={image()!.previewUrl} alt={entry.label} />
191→                            <div class="border-label">{entry.label}</div>
192→                          </div>
193→                        </Show>
194→                      );
195→                    }}
196→                  </For>
197→                </div>
198→              </div>
199→            )}
200→          </For>
201→        </Show>
202→      </div>
203→    </div>
204→  );
205→}
